body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h); 
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }

    .font-syne { font-family: 'Syne', sans-serif; }
    .theme-surface { background: var(--sur); border: 1px solid var(--bdr); color: var(--text); }

    /* Buttons */
    .btn-outline { 
      display:inline-flex; align-items:center; gap:8px; 
      background:transparent; color:var(--primary); 
      font-weight:600; font-size:.9rem; padding:10px 22px; 
      border-radius:50px; border:1.5px solid var(--primary); 
      cursor:pointer; transition:all var(--t); 
    }
    .btn-outline:hover { background:var(--primary); color:#fff; box-shadow: 0 4px 12px rgba(0,102,255,0.2); transform: translateY(-1px); }
    .btn-sm { padding:8px 18px; font-size:.82rem; }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px;
      text-align: center;
    }
    .hero-banner::before {
      content: '';
      position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1;
    }
    .hero-banner::after {
      content: '';
      position: absolute; inset: 0;
      background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.03'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
      z-index: 1;
    }
    .hero-ring {
      position: absolute; border-radius: 50%;
      border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 700px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.5rem);
      font-weight: 800; color: #fff; letter-spacing: -.02em; margin-bottom: 16px;
      text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p {
      font-size: 1.1rem; color: rgba(255,255,255,.75); max-width: 600px; margin: 0 auto; line-height: 1.65;
    }
    @media (max-width: 640px) {
      .hero-banner { padding: 60px 0 80px; }
      .hero-banner h1 { font-size: 2.2rem; }
    }

    /* ========================================================================== */
    /* FILTER CONTROLS                                                            */
    /* ========================================================================== */
    .filter-controls {
      display: flex; gap: 16px; flex-wrap: wrap; align-items: center; 
      margin-bottom: 36px; padding: 20px 28px; 
      background: #fff; border: 1px solid var(--bdr); 
      border-radius: 16px; box-shadow: var(--sh-sm);
    }
    .filter-controls i.bi-funnel-fill { color: var(--primary); font-size: 1.3rem; }
    .filter-controls select, .filter-controls input { 
      flex: 1; min-width: 160px; 
      padding: 12px 16px; border: 1.5px solid var(--bdr); border-radius: 10px; 
      font-family: inherit; font-size: .9rem; font-weight: 500; color: var(--text); 
      background: var(--sur-2); transition: all var(--t); outline: none;
    }
    .filter-controls input { flex: 2; min-width: 220px; }
    .filter-controls select:focus, .filter-controls input:focus {
      border-color: var(--primary); background: #fff; box-shadow: 0 0 0 4px rgba(51,133,255,.1);
    }
    @media (max-width: 640px) {
      .filter-controls { flex-direction: column; align-items: stretch; padding: 18px; border-radius: 12px; }
      .filter-controls select, .filter-controls input { width: 100%; min-width: unset; }
    }

    /* ========================================================================== */
    /* EVENT CARDS (Refined SaaS Styling matching image_c1d583.png)               */
    /* ========================================================================== */
    .events-grid { 
      display: grid; 
      grid-template-columns: repeat(4, 1fr); 
      gap: 24px; 
    }
    @media(max-width:1200px) { .events-grid { grid-template-columns: repeat(3, 1fr); } }
    @media(max-width:900px) { .events-grid { grid-template-columns: repeat(2, 1fr); } }
    @media(max-width:560px) { .events-grid { grid-template-columns: 1fr; } }

    /* Container for stagger animation */
    .ev-card-wrap {
      animation: fadeInSlideUp 0.4s ease-out forwards;
      opacity: 0;
    }
    @keyframes fadeInSlideUp {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }

    .ev-card {
      background: #fff;
      border-radius: 16px;
      overflow: hidden;
      border: 1px solid rgba(0,0,0,0.06);
      box-shadow: var(--sh-sm);
      transition: transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275), box-shadow 0.3s ease;
      cursor: pointer;
      display: flex;
      flex-direction: column;
      height: 100%;
    }
    .ev-card:hover {
      transform: translateY(-8px);
      box-shadow: 0 16px 36px rgba(0,0,0,0.08);
      border-color: rgba(51,133,255,0.15);
    }

    .ev-top {
      aspect-ratio: 16/10;
      position: relative;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 3.5rem; 
      background-size: cover;
      background-position: center;
      background-color: var(--sur-2);
      border-bottom: 1px solid rgba(0,0,0,0.04);
      overflow: hidden;
    }
    .ev-img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      transition: transform 0.5s ease;
    }
    .ev-card:hover .ev-img { transform: scale(1.06); }

    .ev-body {
      padding: 24px;
      display: flex;
      flex-direction: column;
      flex: 1;
    }

    .ev-tags {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 12px;
    }
    .ev-tag-cat {
      font-size: 0.75rem;
      font-weight: 800;
      color: var(--primary-d);
      text-transform: uppercase;
      letter-spacing: 0.05em;
    }
    .ev-tag-status {
      font-size: 0.65rem;
      font-weight: 800;
      padding: 4px 12px;
      border-radius: 50px;
      text-transform: uppercase;
      letter-spacing: 0.05em;
    }
    /* Status Types */
    .ev-tag-upcoming { background: #fffbeb; color: #d97706; }
    .ev-tag-ongoing { background: #eff6ff; color: #2563eb; }
    .ev-tag-completed { background: var(--sur-3); color: var(--text-m); }

    .ev-title {
      font-family: 'DM Sans', sans-serif;
      font-size: 1.25rem;
      font-weight: 800;
      color: var(--primary-d);
      margin-bottom: 18px;
      line-height: 1.35;
      display: -webkit-box;
      -webkit-line-clamp: 2;
      -webkit-box-orient: vertical;
      overflow: hidden;
    }

    .ev-meta-row {
      display: flex;
      gap: 16px;
      font-size: 0.85rem;
      font-weight: 500;
      color: var(--text-s);
      margin-top: auto;
      margin-bottom: 18px;
    }
    .ev-meta-row i { color: var(--primary); margin-right: 5px; font-size: 1rem; vertical-align: middle; }

    .ev-action {
      font-size: 0.85rem;
      color: var(--primary);
      font-weight: 700;
      display: flex;
      align-items: center;
      gap: 8px;
      border-top: 1px solid var(--bdr-s);
      padding-top: 18px;
      transition: gap 0.2s;
    }
    .ev-action i { font-size: 1.1rem; }
    .ev-card:hover .ev-action { gap: 12px; color: var(--primary-2); }

    /* No Results / Loading States */
    .no-results, .loading-state {
      text-align: center; padding: 80px 20px; grid-column: 1 / -1;
      background: #fff; border-radius: 20px; border: 1px dashed var(--bdr);
    }
    .no-results i, .loading-state .spinner-border { font-size: 3.5rem; width: 3.5rem; height: 3.5rem; color: var(--text-m); display: block; margin: 0 auto 16px; opacity: 0.5; }
    .no-results strong, .loading-state strong { font-size: 1.3rem; color: var(--primary-d); display: block; margin-bottom: 8px; font-weight: 800;}

    /* ========================================================================== */
    /* PAGINATION                                                                 */
    /* ========================================================================== */
    .pagination-container {
      display: flex;
      justify-content: center;
      align-items: center;
      gap: 10px;
      margin-top: 48px;
      width: 100%;
    }
    .page-btn {
      width: 42px;
      height: 42px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 10px;
      border: 1.5px solid var(--bdr);
      background: #fff;
      color: var(--text-s);
      font-weight: 700;
      cursor: pointer;
      transition: all var(--t);
    }
    .page-btn:hover:not(:disabled) {
      border-color: var(--primary);
      color: var(--primary);
      background: var(--primary-xl);
      transform: translateY(-2px);
      box-shadow: var(--sh-xs);
    }
    .page-btn.active {
      background: var(--primary);
      color: #fff;
      border-color: var(--primary);
      box-shadow: 0 6px 16px rgba(0, 102, 255, 0.25);
      transform: translateY(-2px);
    }
    .page-btn:disabled {
      opacity: 0.4;
      cursor: not-allowed;
      background: var(--sur-2);
    }

    /* ========================================================================== */
    /* SPLIT-LAYOUT EVENT MODAL (Refined Premium SaaS Design)                     */
    /* ========================================================================== */
    .ev-modal-overlay {
      display: none;
      position: fixed; inset: 0;
      background: rgba(0,14,36,0.65);
      z-index: 10000;
      align-items: center; justify-content: center;
      padding: 20px;
      backdrop-filter: blur(6px);
      -webkit-backdrop-filter: blur(6px);
    }
    .ev-modal-overlay.open { display: flex; }

    .ev-modal {
      width: 860px; max-width: 100%;
      background: #fff;
      border-radius: 24px;
      overflow: hidden;
      box-shadow: 0 24px 60px rgba(0,0,0,0.2);
      animation: modalPop 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      display: flex;
      flex-direction: row;
      position: relative;
    }
    @keyframes modalPop {
      from { transform: scale(0.92); opacity: 0; }
      to { transform: scale(1); opacity: 1; }
    }

    .ev-m-top {
      width: 42%;
      min-height: 420px;
      position: relative;
      display: flex; align-items: center; justify-content: center;
      font-size: 6rem;
      background-size: cover;
      background-position: center;
      background-color: var(--primary-l);
    }
    /* Subtle inner shadow for left pane */
    .ev-m-top::after {
      content: ''; position: absolute; inset: 0;
      box-shadow: inset -10px 0 20px rgba(0,0,0,0.03);
      pointer-events: none;
    }

    .ev-m-body { 
      width: 58%;
      padding: 48px 40px; 
      background: #fff; 
      overflow-y: auto;
      max-height: 85vh;
      position: relative;
    }

    .ev-m-close {
      position: absolute; top: 20px; right: 20px;
      width: 36px; height: 36px; border-radius: 50%;
      background: var(--sur-2); color: var(--text-s); 
      border: 1px solid var(--bdr);
      display: flex; align-items: center; justify-content: center;
      cursor: pointer; font-size: 1.1rem; z-index: 10;
      transition: all 0.2s;
    }
    .ev-m-close:hover { background: var(--primary-xl); color: var(--primary); border-color: var(--primary); transform: scale(1.05); }

    .ev-m-title {
      font-size: 1.8rem; font-weight: 800; color: var(--primary-d);
      margin: 16px 0; line-height: 1.25; font-family: 'DM Sans', sans-serif;
    }
    .ev-m-desc {
      font-size: 0.95rem; color: var(--text-s);
      line-height: 1.7; margin-bottom: 32px;
    }
    .ev-m-list { list-style: none; padding: 0; margin: 0; }
    .ev-m-list li {
      display: flex; align-items: flex-start; gap: 16px;
      padding: 18px 0; border-bottom: 1px solid var(--bdr-s);
    }
    .ev-m-list li:last-child { border-bottom: none; padding-bottom: 0; }

    .ev-m-icon {
      width: 48px; height: 48px; border-radius: 14px;
      background: var(--digital-blue-50); color: var(--digital-blue-600);
      display: flex; align-items: center; justify-content: center;
      font-size: 1.3rem; flex-shrink: 0; border: 1px solid rgba(0,102,255,0.05);
    }
    .ev-m-info { display: flex; flex-direction: column; gap: 4px; padding-top: 2px; }
    .ev-m-label {
      font-size: 0.72rem; font-weight: 800; letter-spacing: 0.08em;
      text-transform: uppercase; color: var(--text-m);
    }
    .ev-m-val { font-size: 1.05rem; font-weight: 700; color: var(--primary-d); }

    .ev-tag-modal-cat {
      font-size: 0.75rem; font-weight: 800; color: var(--primary); 
      text-transform: uppercase; letter-spacing: 0.06em;
      display: inline-block;
    }

    @media (max-width: 768px) {
      .ev-modal { flex-direction: column; width: 92%; }
      .ev-m-top { width: 100%; min-height: 220px; height: 220px; border-right: none; border-bottom: 1px solid var(--bdr-s); }
      .ev-m-top::after { display: none; }
      .ev-m-body { width: 100%; padding: 32px 24px; }
      .ev-m-close { top: 16px; right: 16px; background: rgba(255,255,255,0.9); border-color: transparent; }
      .ev-m-close:hover { background: #fff; }
      .ev-m-title { font-size: 1.5rem; }
    }

