(function() {
    'use strict';

    const API_URL_EVENTS = 'https://gpnainital.com/api/data/events?key=19a1f6a23c02c60c1b4a447b237d5b7c88d6cb3d129c9ec64b8254f917a0c077';

    let currentPage = 1;
    const itemsPerPage = 12;
    let allEventsData = []; // Store raw API data

    /* ── HELPER: Sanitize Image URLs ── */
    function sanitizeUrl(url) {
      if (!url) return '';
      return url.replace(/http:\/\/192\.168\.1\.2:8000/gi, 'https://gpnainital.com');
    }

    /* ── FETCH EVENTS API ── */
    async function fetchEvents() {
      const grid = document.getElementById('eventsGrid');
      const loading = document.getElementById('loadingEvents');
      const noEvents = document.getElementById('noEvents');

      try {
        const res = await fetch(API_URL_EVENTS);
        if (!res.ok) throw new Error('API Error');
        const data = await res.json();
        allEventsData = data.data || (Array.isArray(data) ? data : []);

        loading.style.display = 'none';

        if (allEventsData.length > 0) {
          renderAllEventsToDOM(allEventsData);
          window.filterEvents(1); // Trigger pagination & filters
        } else {
          noEvents.style.display = 'block';
        }
      } catch (err) {
        console.error("Failed to load events:", err);
        loading.style.display = 'none';
        noEvents.querySelector('strong').innerText = "Failed to load events.";
        noEvents.querySelector('p').innerText = "Please try refreshing the page.";
        noEvents.style.display = 'block';
      }
    }

    /* ── RENDER EVENTS TO DOM (Hidden initially) ── */
    function renderAllEventsToDOM(events) {
      const grid = document.getElementById('eventsGrid');
      grid.innerHTML = ''; // Clear loading spinner

      events.forEach((ev, index) => {
        const typeLower = ev.type ? ev.type.toLowerCase() : 'general';
        const safeImageUrl = sanitizeUrl(ev.image_url || ev.image);
        const safeFileUrl = sanitizeUrl(ev.file_url || ev.fileUrl);
        const evDate = ev.event_date || ev.date || '';

        // Dynamic Emoji fallback if no image is present
        let emoji = '📅';
        if (typeLower === 'sports') emoji = '🏃';
        else if (typeLower === 'workshop') emoji = '🔬';
        else if (typeLower === 'cultural') emoji = '🎭';
        else if (typeLower === 'seminar') emoji = '💻';
        else if (typeLower === 'academic') emoji = '🎓';

        // Background Color Mapping
        const bgColors = {
          'sports': '#1d4ed8', 'workshop': '#9333ea', 'cultural': '#db2777', 
          'seminar': '#059669', 'academic': '#003d99', 'placement': '#d97706', 'general': 'var(--primary)'
        };
        const bg = bgColors[typeLower] || bgColors['general'];

        // Extract Status or default to Upcoming
        const status = ev.status ? ev.status.toLowerCase() : 'upcoming';

        const wrap = document.createElement('div');
        wrap.className = 'ev-card-wrap';
        // Keep hidden until pagination reveals them
        wrap.style.display = 'none';

        wrap.innerHTML = `
          <div class="ev-card" data-status="${status}" data-type="${typeLower}">
            <div class="ev-top" style="background-color: ${bg}; ${safeImageUrl ? `background-image: url('${safeImageUrl}');` : ''}">
               ${safeImageUrl ? '' : emoji}
            </div>
            <div class="ev-body">
              <div class="ev-tags">
                <span class="ev-tag-cat">${ev.type || 'EVENT'}</span>
              </div>
              <div class="ev-title">${ev.title}</div>
              <div class="ev-meta-row">
                <div><i class="bi bi-calendar3"></i> ${evDate}</div>
                <div><i class="bi bi-geo-alt"></i> ${ev.venue || 'TBA'}</div>
              </div>
              <div class="ev-action"><i class="bi bi-eye"></i> View Details</div>
            </div>
          </div>
        `;

        // Bind Modal click event to the card
        const card = wrap.querySelector('.ev-card');
        card.addEventListener('click', () => {
            document.getElementById('evMTop').style.backgroundColor = bg;
            if (safeImageUrl) {
              document.getElementById('evMTop').style.backgroundImage = `url('${safeImageUrl}')`;
              document.getElementById('evMIcon').style.display = 'none';
            } else {
              document.getElementById('evMTop').style.backgroundImage = 'none';
              document.getElementById('evMIcon').textContent = emoji;
              document.getElementById('evMIcon').style.display = 'flex';
            }

            document.getElementById('evMCat').textContent = ev.type || 'EVENT';
            document.getElementById('evMTitle').textContent = ev.title;
            document.getElementById('evMDesc').textContent = ev.description || ev.desc || 'No description available.';
            document.getElementById('evMDate').textContent = evDate || 'TBA';
            document.getElementById('evMVenue').textContent = ev.venue || 'TBA';
            document.getElementById('evMOrg').textContent = ev.organizer || 'UGIP Administration';

            // Attachment Logic 
            const docContainer = document.getElementById('evMDocContainer');
            const docLink = document.getElementById('evMDocLink');
            if (safeFileUrl && safeFileUrl.trim() !== '') {
                docLink.href = safeFileUrl;
                docContainer.style.display = 'flex';
            } else {
                docContainer.style.display = 'none';
            }

            document.getElementById('evModalOverlay').classList.add('open');
            document.body.style.overflow = 'hidden';
        });

        grid.appendChild(wrap);
      });
    }

    /* ── FILTER AND PAGINATION LOGIC ── */
    window.filterEvents = function(page = 1) {
      currentPage = page;
      const status = document.getElementById('statusFilter').value;
      const type = document.getElementById('typeFilter').value;
      const q = document.getElementById('searchInput').value.toLowerCase();

      // Get all card wrappers
      const wrappers = Array.from(document.querySelectorAll('.ev-card-wrap'));

      // Filter items
      const filtered = wrappers.filter(wrap => {
        const c = wrap.querySelector('.ev-card');
        const cStatus = c.dataset.status || '';
        const cType = c.dataset.type || '';
        const cTitle = c.querySelector('.ev-title').innerText.toLowerCase();

        const matchStatus = status === 'all' || cStatus === status;
        const matchType = type === 'all' || cType === type;
        const matchQuery = !q || cTitle.includes(q);

        return matchStatus && matchType && matchQuery;
      });

      // Hide all first, remove animation classes
      wrappers.forEach(w => {
        w.style.display = 'none';
        w.style.animation = 'none';
      });

      // Calculate Pagination
      const totalPages = Math.ceil(filtered.length / itemsPerPage);
      if (currentPage > totalPages && totalPages > 0) currentPage = totalPages;

      const startIndex = (currentPage - 1) * itemsPerPage;
      const endIndex = startIndex + itemsPerPage;

      // Show only paginated slice with staggered animation
      filtered.slice(startIndex, endIndex).forEach((w, index) => {
        w.style.display = 'block';
        // Trigger reflow to restart animation
        void w.offsetWidth;
        w.style.animation = `fadeInSlideUp 0.4s ease-out forwards`;
        w.style.animationDelay = `${index * 0.05}s`;
      });

      document.getElementById('noEvents').style.display = filtered.length === 0 ? 'block' : 'none';

      // Render Pagination Buttons
      renderPagination(totalPages);
    };

    function renderPagination(totalPages) {
      const container = document.getElementById('paginationContainer');
      container.innerHTML = '';
      if (totalPages <= 1) return; // Don't show pagination if 1 page or less

      // Previous Button
      const prevBtn = document.createElement('button');
      prevBtn.className = 'page-btn';
      prevBtn.innerHTML = '<i class="bi bi-chevron-left"></i>';
      prevBtn.disabled = currentPage === 1;
      prevBtn.onclick = () => window.filterEvents(currentPage - 1);
      container.appendChild(prevBtn);

      // Page Numbers
      for (let i = 1; i <= totalPages; i++) {
        const btn = document.createElement('button');
        btn.className = `page-btn ${i === currentPage ? 'active' : ''}`;
        btn.innerText = i;
        btn.onclick = () => {
          window.filterEvents(i);
          window.scrollTo({ top: document.querySelector('.filter-controls').offsetTop - 120, behavior: 'smooth' });
        };
        container.appendChild(btn);
      }

      // Next Button
      const nextBtn = document.createElement('button');
      nextBtn.className = 'page-btn';
      nextBtn.innerHTML = '<i class="bi bi-chevron-right"></i>';
      nextBtn.disabled = currentPage === totalPages;
      nextBtn.onclick = () => window.filterEvents(currentPage + 1);
      container.appendChild(nextBtn);
    }

    window.resetFilters = function() {
      document.getElementById('statusFilter').value = 'all';
      document.getElementById('typeFilter').value = 'all';
      document.getElementById('searchInput').value = '';
      window.filterEvents(1);
    };

    /* ── MODAL CLOSE LOGIC ── */
    const overlay = document.getElementById('evModalOverlay');
    const closeBtn = document.getElementById('evMClose');

    function closeEvModal() {
      overlay.classList.remove('open');
      document.body.style.overflow = '';
    }

    if(closeBtn) closeBtn.addEventListener('click', closeEvModal);
    if(overlay) overlay.addEventListener('click', e => {
      if (e.target === overlay) closeEvModal();
    });
    document.addEventListener('keydown', e => {
      if (e.key === 'Escape') closeEvModal();
    });

    /* ── INIT APP ── */
    // Wait for DOM
    document.addEventListener('DOMContentLoaded', () => {
      // Clean up any injected favicons causing Mixed Content/Timeout errors
      document.querySelectorAll('link[rel="icon"], link[rel="shortcut icon"], link[rel="apple-touch-icon"]').forEach(link => {
        if (link.href && link.href.includes('192.168.1.2:8000')) {
          link.href = link.href.replace(/http:\/\/192\.168\.1\.2:8000/gi, 'https://gpnainital.com');
        }
      });

      fetchEvents();
    });

  })();
